const config = $('Call \'CONFIG — Global Settings\'').first().json;
const queries = config.leadSourcingQueries;

return queries.map(query => ({
  json: { query: query, config: config }
}));

const response = $('Google Maps Places Search').first().json;
const results = Array.isArray(response.results) ? response.results : [];
const batchItem = $('Process Each Query').first().json;
const query = (batchItem && batchItem.query) ? String(batchItem.query) : '';
return results.map(place => ({
  json: {
    businessName: place.name != null ? String(place.name) : '',
    address: place.formatted_address != null ? String(place.formatted_address) : '',
    rating: typeof place.rating === 'number' ? place.rating : 0,
    reviewCount: typeof place.user_ratings_total === 'number' ? place.user_ratings_total : 0,
    placeId: place.place_id != null ? String(place.place_id) : '',
    hasPhone: false,
    hasWebsite: false,
    phone: '',
    website: '',
    sourcingQuery: query
  }
}));

const detailItems = $input.all();
const placeItems = $('Extract Place Data').all();

return detailItems.map((detailItem, index) => {
  const detailJson = detailItem && detailItem.json ? detailItem.json : {};
  const result = detailJson.result || {};
  const placeJson = placeItems[index] && placeItems[index].json ? placeItems[index].json : {};

  let phone = result.international_phone_number || result.formatted_phone_number || '';
  phone = String(phone).replace(/[^+\d]/g, '');
  if (phone && !phone.startsWith('+')) phone = '+1' + phone;

  const website = result.website != null ? String(result.website) : '';

  return {
    json: {
      businessName: placeJson.businessName != null ? String(placeJson.businessName) : '',
      address: placeJson.address != null ? String(placeJson.address) : '',
      rating: typeof placeJson.rating === 'number' ? placeJson.rating : 0,
      reviewCount: typeof placeJson.reviewCount === 'number' ? placeJson.reviewCount : 0,
      placeId: placeJson.placeId != null ? String(placeJson.placeId) : '',
      hasPhone: !!phone,
      hasWebsite: !!website,
      phone: phone,
      website: website,
      sourcingQuery: placeJson.sourcingQuery != null ? String(placeJson.sourcingQuery) : ''
    }
  };
});

let sheetRows = [];
try {
  const readNode = $('Read Leads Sheet').all();
  if (readNode && Array.isArray(readNode) && readNode.length > 0 && !readNode[0].json?.error) {
    sheetRows = readNode;
  }
} catch (e) {}
const existingPlaceIds = new Set(
  sheetRows
    .map(r => r.json && (r.json['Place ID'] != null || r.json.placeId != null)
      ? String(r.json['Place ID'] || r.json.placeId).trim()
      : '')
    .filter(Boolean)
);
const items = $('Enrich with Details').all();
const filtered = items.filter(item => {
  const pid = item.json && item.json.placeId ? String(item.json.placeId).trim() : '';
  return pid && !existingPlaceIds.has(pid);
});
return filtered.map(item => ({ json: item.json }));

const place = $('Loop Over Leads').first().json;
let score = 0;
if (place.hasPhone) score += 2;
if (place.hasWebsite) score += 2;
if (typeof place.rating === 'number' && place.rating >= 4.0) score += 2;
if (typeof place.reviewCount === 'number') {
  if (place.reviewCount >= 100) score += 2;
  else if (place.reviewCount >= 50) score += 1;
}
const config = $('Call \'CONFIG — Global Settings\'').first().json;
const hotThreshold = config.scoring?.hotLeadThreshold || 7;
const warmThreshold = config.scoring?.warmLeadThreshold || 4;
let tier = 'cold';
if (score >= hotThreshold) tier = 'hot';
else if (score >= warmThreshold) tier = 'warm';
return [{ json: { success: true, data: { score, tier } } }];

